VALUES ('1690849425331x799804717758152700', 'A Fonte iPhones', '42.370.832/0001-40', 'jhonatacirulli9@gmail.com', '(19) 9 9848-4796', NULL, 'Rua Santa cruz 754 Sala 51 Centro Limeira SP', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1690901518143x498729589409983200/WhatsApp%20Image%202023-08-01%20at%2011.51.33.jpeg', NULL, 'Essencial', 'Mensal', '2025-07-12T08:27:00', '2025-01-23T22:30:00', NULL, NULL, NULL, true, true, false, false, false, false, false, true, true, true, false, true, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, 'cus_000063378846', NULL, NULL, '1759220466839x407976978981757600', NULL, 'https://www.asaas.com/i/fc4sdx085xk90373', NULL, NULL, NULL, 'TERMO DE GARANTIA: VALIDADE: 3 MESES PARA APARELHOS SEMI NOVOS. NÃO ESTÃO INCLUSOS NA GARANTIA MAU USO COMO: APARELHO MOLHADO OU EXPOSTO A UMIDADE, TRINCADOS OU QUEBRADOS, RISCOS, MANCHAS, BEM COMO OCASIÃO DE QUEDAS, ESMAGAMENTOS, SOBRECARGA ELÉTRICA, EXPOSIÇÃO DO APARELHO A ALTAS TEMPERATURAS, ABERTURA DO EQUIPAMENTO OU TENTATIVA DE CONSERTO DESTE POR TERCEIROS QUE NÃO SEJAM OS TÉCNICOS INDICADOS PELO(A) VENDEDOR (A) QUE OFERECE ESSA GARANTIA, COM CAPACITAÇÃO OU CERTIFICAÇÃO DA APPLE. EM CASO DE TROCA SOLICITAMOS UM PRAZO DE 5 DIAS ÚTEIS PARA A SOLUÇÃO DO PROBLEMA OU A SUBSTITUIÇÃO DO APARELHO. ABAIXO DO SEU APARELHO HÁ UM SELO DE GARANTIA QUE CERTIFICA QUE SEU APARELHO FOI COMPRADO CONOSCO. FAVOR NÃO RETIRAR OU VIOLAR, CASO CONTRÁRIO A GARANTIA É PERDIDA. EM CASO DE TROCA, NÃO GARANTIMOS A MESMA PORCENTAGEM DE BATERIA.', 'PADRAO', '2023-07-31T21:23:00', '2026-01-09T10:05:00', 'jhonatacirulli9@gmail.com');
