VALUES ('1690898511982x355404569342902300', 'RDGSTORE', '405.872.448-01', 'rdgstore2023@gmail.com', '(11) 9 4933-6637', '@rdgapple_store', 'AV CUPECE 3128', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1715098088317x606361560707605600/Imagem%2016-02-2024%20a%CC%80s%2001.28.jpeg', NULL, 'Gerencial', 'Mensal', '2025-08-06T09:00:00', '2026-01-29T15:46:00', NULL, 2, NULL, true, true, false, false, false, false, true, true, true, true, false, true, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, 'cus_000061120104', NULL, NULL, '1759220466457x155524047326416350', '2', NULL, NULL, NULL, NULL, 'I. A garantia cobre os aparelhos lacrados/novos contra defeitos de fabricação durante um ano e cobre durante 03 (três) meses os aparelhos seminovos, contado da data da compra pelo usuário final.  II. Aparelhos que apresentarem defeitos de fábrica (constatados por pericia técnica) em até sete dias corridos após a compra, a empresa se compromete em trocar o mesmo, por outro aparelho de mesmo modelo e qualidades, sem custo algum para o(a) cliente.  III. A garantia não abrange o funcionamento, instalação e atualização de aplicativos, bem como o sistema operacional do aparelho; Qualquer mau funcionamento APÓS ATUALIZAÇÕES do sistema operacional ou aplicativos; Limpeza e conservação do aparelho. IV. Os atendimentos no que tange à garantia dos aparelhos, serão prestados na loja física da empresa, ficando desde já o cliente ciente, que é de sua responsabilidade levar e buscar o aparelho, no referido endereço, caso necessite de garantia. V. No ato da compra, o cliente declara que foi informado que o WhatsApp específicos/oficiais para tratativas sobre garantia dos aparelhos é o telefone no cabeçalho da nota.', 'PADRAO', '2023-08-01T11:01:00', '2026-01-29T15:46:00', 'rdgstore2023@gmail.com');
INSERT INTO empresas (bubble_unique_id, nome, cnpj, email, telefone, instagram, endereco, logo_url, slug, plano, recorrencia, acesso_ate, ultimo_acesso, limite_usuarios, qtd_vendedores, usuario_adicional, ativo, cadastro_completo, primeiro_acesso, aguardando_aprovacao, beta, super_beta, novos_modelos, novas_cores, info_pagto_assinatura, assinatura_irregular, primeiro_pagto, adiciona_dias, fiscal_ativo, fiscal_cnpj, fiscal_ie, regime_tributario, certificado_ref, rf_fiscal_ref, addon_assistencia, addon_emp_fiscal, addon_os_planos, asaas_customer_id, assinatura_ref, api_key, project_ref, carteira_ref, engajamento_ref, fatura_url, configuracoes_gerais, crm_acesso_ate, termos, termo_empresa, id_visual, created_at, updated_at, created_by)
VALUES ('1690898594432x893478644023296000', 'Grupo iTech', '39.683.695/0001-99', 'isabellacarolina@sejaitech.com.br', '(11) 9 7057-3103', '@Aiphone.cell', 'Rua Vergueiro, 2253, Vila Mariana/SP - CEP 04101100', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1701717621846x444606834720138600/WhatsApp%20Image%202023-11-23%20at%2015.58.37.jpeg', NULL, 'Gerencial', 'Anual', '2026-10-24T10:00:00', '2026-02-04T08:06:00', NULL, 6, 19, true, true, false, false, false, false, true, true, true, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, 'cus_000062711940', 'cus_000062711940', NULL, NULL, '1759220466348x858042090660080300', '149', NULL, 'Atendimento com abertura de caixa , Movimentação financeira com abertura de caixa , Emissão fiscal com abertura de caixa , Ordem de serviço com abertura de caixa , Informar motivo de cancelamento do Atendimento , Informar motivo de cancelamento da Ordem de Serviço , Informar motivo de cancelamento de Compra', NULL, NULL, 'iTech fornece uma garantia SOMENTE para as peças com defeitos de fabricação e funcionamento, referente a produtos trocados no iphone de alta qualidade.   Fica estabelecido, para tanto, o prazo de 90 (noventa) dias. A contagem deverá iniciar, a partir do recebimento do aparelho.No caso de problemas ou vício oculto, o aparelho deverá ser direcionado para iTech, onde ficará em análise pelo nosso técnico especializado no prazo de até 7 dias úteis, para assim dar a resposta do reparo ou troca do aparelho.   O reparo ou troca poderá se estender em até 30 dias após a análise para execução do procedimento no aparelho ou troca conforme determinado por lei, pois trabalhamos com produtos de alta complexidade.   iTech é a única empresa que poderá realizar a abertura e quebra do lacre do produto, uma vez que se trata da empresa garantidora. Fica proibido a abertura do produto por qualquer uma empresa de assistência, sendo ou não autorizada do fabricante. Esclarecido que os produtos semi novos, podem ter peças internas trocadas antes do momento da venda.   A política de garantia acima estabelecida, apenas realiza troca dos aparelhos defeituosos, pelo mesmo aparelho que deverá ser reparado ou em caso de troca, deverá ser por outro do mesmo modelo e categoria (seminovo) em perfeito estado de funcionamento. Caso o consumidor tenha interesse na troca do aparelho por outro modelo diferente do adquirido, o aparelho será reavaliado, aplicando para o mesmo a tabela diferenciada para abatimento de valores da iTech. Não será realizada a devolução dos valores, em nenhuma hipótese, uma vez que a lei determinada este procedimento SOMENTE para compras realizadas virtualmente, o que não foi praticado neste caso, uma vez que o consumidor declara neste ato ter sido está uma compra presencial na loja. Não será possível a troca do produto, caso o mesmo apresente problema ou defeito após decorridos os 90 (Noventa) dias.  iTech recomenda a conservação do comprovante de compra e o número IMEI de seu produto, uma vez que a mesma não tem a obrigação de guardar o respectivo comprovante.  O consumidor tem ciência que o aparelho semi novo, pode ter sido ativado, haja vista que se trata de aparelhos usados. O mesmo pode ter sido reparado e trocado peças para entregar em perfeito estado conforme o checklist de entrega do aparelho.   Declara, ainda, o consumidor que no caso de troca de peça, o mesmo deverá arcar com os custos, no caso de isenção e exclusão desta garantia. O consumidor declara que no ato da compra, conferiu a situação e apresentação do aparelho e imei, bem como declara que o mesmo não possui qualquer defeito, renunciando o direito de questionamento pré processual ou judicial.  Para efeitos de TROCA não são considerados defeitos de fabricação: 1) Defeitos ou danos resultantes do mau uso, como telas quebradas, rachadas, display manchado e entre outros problemas similares; 2) Conserto realizado por outra assistência técnica dentro dos 90 (Noventa) dias; 3) Produtos que tenham tido o lacre de segurança rompido, número de série removido, adulterado ou tomado ilegível; 4) Danos por fluidos, como por exemplo, danos causados por contato com água;Todos os itens descritos acima anulam automaticamente a garantia prestada por iTech.', 'PADRAO', '2023-08-01T11:03:00', '2026-02-04T08:06:00', 'daniloroos@sejaitech.com.br');
