VALUES ('1691012227895x319103986746261500', 'Gss iPhones', '41.335.796/0001-10', 'gss_iphones@hotmail.com', NULL, '@gss_iphones', 'Av. Eng. Armando de Arruda Pereira, 2937 - Jabaquara, São Paulo - SP, 04309-011', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1696967618866x106019661516214340/logo%20apple.jpeg', NULL, 'Gerencial', 'Mensal', '2023-11-12T16:47:00', NULL, NULL, 3, NULL, true, true, false, false, false, false, false, false, true, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, 'cus_000065837472', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'O	que a garantia	não cobre?  Fique atento aos tópicos abaixo, eles não são considerados como defeito de fabricação:   1- Defeitos ou	danos	resultantes do mau	uso,	como telas quebradas, rachadas, entre outros	problemas similares.  2- Defeitos ou danos decorrentes de testes, instalação, alteração, modificação de qualquer	espécie em nossos	produtos, bem	como o conserto	realizado	em alguma assistência	técnica.  4- Danos por fluidos, como	por exemplo, danos causados por contato com	água.  5- Redução	aceitável da vida	útil da bateria.  6- Roubo	ou furto do aparelho.', 'PADRAO', '2023-08-02T18:37:00', '2026-01-09T10:05:00', 'gss_iphones@hotmail.com');
