VALUES ('1691585652601x917757108518387700', 'Mariana Ferraz', '442.973.558-17', 'mariribfer@gmail.com', '(17) 9 9600-1709', 'marih_ferraz', 'Online', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1691585835796x821065707142319700/WhatsApp%2520Image%25202023-08-02%2520at%252015.07.54%5B1%5D.jpeg', NULL, 'Inativo', 'Mensal', '2024-01-04T10:35:00', NULL, NULL, 123, NULL, false, true, false, false, false, false, false, false, true, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, 'cus_000065352085', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '[b]I. [/b][i]Aparelhos lacrados/novos ou seminovos dentro da garantia Apple, a cobertura da mesma somente é feita pelo prazo em que durar a própria garantia da marca, devendo o comprador entrar em contato com o atendimento ao cliente ou solicitar ajuda do lojista para o mesmo.[/i] [b]II. [/b][i]Aparelhos cujo a garantia não é coberta pela Apple, é de responsabilidade da loja ceder 4 meses para o reparo ou manutenção caso tenha ocorrido problemas internos de fabrica do aparelho, não havendo substituição ou troca por um novo.[/i] [b]III. [/b][i]Em casos de quedas ou problemas decorrentes do mal uso do aparelho, a garantia dada pela loja em seminovos não cobrirá, sendo de total responsabilidade do comprador.[/i] [i]﻿[/i]', 'PADRAO', '2023-08-09T09:54:00', '2026-01-05T18:44:00', 'mariribfer@gmail.com');
