VALUES ('1692203243556x708907023181021200', 'Lp imports', '50.671.202/0001-33', 'luizlipecr@gmail.com', '(31) 9 9401-3446', 'lp_iimports_', 'avenida governador Valadares, 199, Betim-MG-CEP32600115', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1692203733811x491505419431863740/WhatsApp%20Image%202023-03-28%20at%2011.18.32.jpeg', NULL, 'Inativo', NULL, '2023-08-23T13:27:00', NULL, NULL, 1, NULL, false, true, false, false, false, false, false, false, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '[b]Lp Imports: GARANTIA É CANCELADA AUTOMATICAMENTE NOS SEGUINTES CASOS:[/b]  [b]1)Quedas. esmagamentos. sobrecarga elétrica. exposição do aparelho a altas temperaturas. umidade ou líquidos, Oxidação ou quebra de alguma peça exposição do aparelho a poeira. [/b] [b]2)Quando constatado mau uso do aparelho, abertura do equipamento ou tentativa de conserto deste por terceiros que não sejam os técnicos da Lp Imports.[/b] [b] 3)Reparos em outros equipamentos que não sejam celulares não tem a GARANTIA LEGAL DE 90 DIAS.[/b] [b]4) NÃO fazemos devolução do dinheiro.[/b] [b]5) A troca levará o tempo que for necessário dentro da necessidade do momento. Em casos de defeitos de funcionamento, que a garantia cobre, poderá ser feito o reparo (quando for algo simples); ou em Extrema necessidade a troca do aparelho dentro da disponibilidade do estoque.[/b] [b]6)﻿A GARANTIA é válida somente para o item ou serviço descrito na ordem de serviço ou neste termo de garantia, NÃO ABRANGENDO OUTRAS PARTES e respeitando as condições acima.[/b]', 'PADRAO', '2023-08-16T13:27:00', '2026-01-06T13:26:00', 'luizlipecr@gmail.com');
