VALUES ('1694879915502x509329662502502400', 'UP NET CELULARES', '38.167.167/0001-14', 'cesarsouza199@gmail.com', '(62) 9 9298-8615', '@upnetcelulares', 'Av. Padre Wendel, Qd. 563, Lt. 10, Sala 05 St. Aeroviário', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1694880106353x209502695687478370/LOGO%20UP%20NET%20CINZA.png', NULL, 'Inativo', NULL, '2023-09-23T12:58:00', NULL, NULL, 1, NULL, false, true, false, false, false, false, false, false, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ATENÇÃO: NÃO REMOVE O SELO DO APARELHO NA PARTE DE BAIXO AO LADO ONDE CARREGA SEM SELO NAO TEM GARANTIA!  Estão cobertos pela garantia as seguintes peças: placa mãe/processador, conector de carga, bateria, câmeras, microfone, auto falante inferior e superior, chip wi-fi/4g/bluetooth/gps, sensor de aproximação.  A GARANTIA É CANCELADA AUTOMATICAMENTE NOS SEGUINTES CASOS: Problemas de software, problemas em aplicativos de terceiros, modificações no sistema operacional ou nas opções de desenvolvedor. Também não recomendamos o uso de temas e modificações no launcher, bem como esmagamentos, sobrecarga elétrica, exposição do aparelho a altas temperaturas, umidades ou líquidos, exposição do aparelho a poeira, pó/e ou limalha de metais, ou ainda quando constatado mau uso do aparelho, instalações e modificações no seu sistema operacional, abertura do equipamento ou tentativa de conserto deste por terceiros que possam assim, danificar o aparelho.  NÃO NOS RESPONSABILIZAMOS POR DANOS EVENTUAIS CAUSADOS POR MAU USO PELA PARTE DO COMPRADOR.  Vale lembrar que: 1) A GARANTIA DE 90 (NOVENTA) dias está de acordo com o artigo 26 inciso II do código de defesa do consumidor. 2) Funcionamento, instalação e atualização de aplicativos, bem como o sistema operacional do aparelho NÃO FAZEM parte desta garantia. 3) Limpeza e conservação do aparelho NÃO FAZEM parte desta garantia. 4) A não apresentação de documento (nota fiscal ou este termo) que comprove o serviço INVÁLIDA a garantia. 5) Qualquer mal funcionamento APÓS ATUALIZAÇÕES do sistema operacional ou aplicativos NÃO FAZEM PARTE DESSA GARANTIA. 6) A GARANTIA é válida somente para o item ou serviço descrito na ordem de serviço ou neste termo de garantia, NÃO ABRANGENDO OUTRAS PARTES e respeitando as condições aqui descritas. 7) SEM SELO NO APARELHO A GARANTIA NÃO COBRE!', 'PADRAO', '2023-09-16T12:58:00', '2026-01-06T13:26:00', 'cesarsouza199@gmail.com');
INSERT INTO empresas (bubble_unique_id, nome, cnpj, email, telefone, instagram, endereco, logo_url, slug, plano, recorrencia, acesso_ate, ultimo_acesso, limite_usuarios, qtd_vendedores, usuario_adicional, ativo, cadastro_completo, primeiro_acesso, aguardando_aprovacao, beta, super_beta, novos_modelos, novas_cores, info_pagto_assinatura, assinatura_irregular, primeiro_pagto, adiciona_dias, fiscal_ativo, fiscal_cnpj, fiscal_ie, regime_tributario, certificado_ref, rf_fiscal_ref, addon_assistencia, addon_emp_fiscal, addon_os_planos, asaas_customer_id, assinatura_ref, api_key, project_ref, carteira_ref, engajamento_ref, fatura_url, configuracoes_gerais, crm_acesso_ate, termos, termo_empresa, id_visual, created_at, updated_at, created_by)
VALUES ('1695140897655x993480806804750300', 'Loren Phone', '47.038.006/0001-11', 'lorenaappleoficial@gmail.com', '(12) 9 8803-2044', 'loren.apple', 'Rua Major Oliveira Borges, 126, Centro, Lorena/SP - CEP 12.600-020', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1699107725449x839896453879126000/https___51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io_f1698783690173x241484902299094600_Imagem.jpg', NULL, 'Gerencial', 'Anual', '2026-10-29T22:34:00', '2026-02-04T10:13:00', NULL, 1, 1, true, true, false, false, false, false, true, true, true, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, 'cus_000064758153', NULL, NULL, '1759220462466x242018423662959230', '107', NULL, NULL, NULL, NULL, '[justify]I. A garantia cobre os aparelhos lacrados/novos contra defeitos de fabricação durante um ano e cobre durante seis meses os aparelhos seminovos, contado da data da compra pelo usuário final. II. Aparelhos que apresentarem defeitos de fábrica (constatados por pericia técnica) em até sete dias corridos após a compra, a empresa se compromete em trocar o mesmo, por outro aparelho de mesmo modelo e qualidades, sem custo algum para o(a) cliente. III. A garantia não abrange funcionamento, instalação e atualização de aplicativos, bem como o sistema operacional do aparelho; A garantia cobre defeitos de fabricação e mau funcionamento dos componentes, como: falha no conector de carga, mau funcionamento do Touch, câmera e afins.[/justify] [justify] [/justify] A garantia, não cobre defeitos oriundos de mau uso do consumidor, como quebras por queda do aparelho, aparecimento de manchas roxas, pretas, esverdeada, vermelhas, listras horizontais ou verticais, listras pretas e esverdeadas, tela totalmente branca ou totalmente preta, que são causadas por pressão excessiva, bateria inflada. Perde ainda a garantia, aparelhos que tenham molhado ou passado por vapor, que tenham tido contato com areia, alimentos, oxidação, sobrecarga elétrica, exposição a altas temperaturas, bem como vidros quebrados e ainda tela. Qualquer mau funcionamento APÓS ATUALIZAÇÕES do sistema operacional ou aplicativos; .IV. Os atendimentos no que tange à garantia dos aparelhos, serão prestados na loja física da empresa, ficando desde já o cliente ciente, que é de sua responsabilidade levar e buscar o aparelho, no referido endereço, caso necessite de garantia. No ato da compra, o cliente declara que foi informado que o WhatsApp específicos/oficiais para tratativas sobre garantia dos aparelhos é o telefone no cabeçalho da nota. V. Nossos aparelhos possuem um selo de garantia na parte inferior próximo ao conector de carga, onde o mesmo devera permanecer durante o período da garantia.', 'PADRAO', '2023-09-19T13:28:00', '2026-02-04T10:13:00', 'lorenaappleoficial@gmail.com');
