VALUES ('1696432968773x476663890039537660', 'IP STORE BR', '42.430.069/0001-03', 'ipstorebr@hotmail.com', '(11) 9 4111-9121', 'ipstorebr', 'Rua Catiguá, 159', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1697549795967x808460806628789900/LOGO%20IP%20STORE%20PRETO%20%28PDF%29%20%281%29_page-0001.jpg', NULL, 'Gerencial', 'Mensal', '2026-02-17T07:48:00', '2026-02-04T09:28:00', NULL, 4, 10, true, true, false, false, false, false, true, true, true, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, 'cus_000066098885', 'cus_000066098885', NULL, NULL, '1759220462327x106286201351300850', '120', NULL, NULL, NULL, NULL, 'A GARANTIA É CANCELADA AUTOMATICAMENTE NOS SEGUINTES CASOS:Em ocasião de quedas, esmagamentos, sobrecarga elétrica; exposição do aparelho a altas temperaturas, umidade ou líquidos; exposição do aparelho a poeira, pó e/ou limalha de metais, ou ainda quando constatado mau uso do aparelho, instalações, modificações ou atualizações no seu sistema operacional; abertura do equipamento ou tentativa de conserto deste por terceiros que não sejam os técnicos da IP STORE BR, mesmo que para realização de outros servicos; bem como a retirada violação do selo/lacre de garantia colocado pela IP STORE BR.A GARANTIA DE 90 (NOVENTA) dias está de acordo com o artigo 26 inciso Il do código de defesa do consumidor.2) Funcionamento, instalação e atualização de aplicativos, bem como o sistema operacional do aparelho NÃO FAZEM parte desta garantia.3) Limpeza e conservação do aparelho NÃO FAZEM parte desta garantia.4) Proibida a remoção ou violação do selo/lacre colocado no aparelho pela própria empresa. (IP STORE BR)5) Qualquer mal funcionamento APÓS ATUALIZAÇÕES do sistema operacional ou aplicativos NÃO FAZEM PARTEDESSA GARANTIA.6) A GARANTIA é válida somente para o item ou serviço descrito na nota fiscal, ordem de serviço ou neste termo de garantia, NÃO ABRANGENDO OUTRAS PARTES e respeitando as condições aqui descritas.', 'PADRAO', '2023-10-04T12:22:00', '2026-02-04T09:28:00', 'ipstorebr@hotmail.com');
