VALUES ('1697004214407x481701730225225700', 'COBRE TUDO PHONES', '54.088.402/0001-19', 'patrickdio1994@outlook.com', '(13) 9 8804-9301', '@cobretudophones', 'Rua Benjamin Constant 61 Sala 2113 Andar 21- Centro-São Vicente- Ed. Helbor', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1705154981637x144246853854815840/thumbnail_02%20Logo%20-%20Quadrado%20sem%20informa%C3%A7%C3%B5es.jpg', NULL, 'Gerencial', 'Anual', '2026-12-22T15:40:00', '2026-02-04T10:51:00', NULL, 2, NULL, true, true, false, false, false, false, true, true, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, 'cus_000075091940', 'cus_000075091940', NULL, NULL, '1759220462238x801508371382399900', '117', NULL, NULL, NULL, NULL, 'PrezadoA COBRE TUDO PHONES, representada por Patrick Dio Ferreira Demésio LTDA CNPJ: 50.490,160.0001-34, oferece garantia sobre o produto adquirido, contra qualquer defeito de fabricação que o mesmo venha a apresentar, conforme os prazos abaixo:Nossos prazos de garantia:• iPhone LACRADO: 01 ano de garantia.• iPhone VITRINE/SEMINOVO: 3 meses de garantia, 90 dias.• XIAOMI LACRADO: 3 meses de garantia, 90 dias.• XBOX LACRADO: 01 ano de garantia.• AIRPODS LACRADO: 01 ano de garantia.• MACBOOK LACRADO: 01 ano de garantia.• PS5 LACRADO: 01 ano de garantia. APARELHOS DE VITRINES SEM SELO SEM GARANTIA. NÃO DEVOLVEMOS DINHERO. NO CASO DE COMPRAS REALIZADAS EM LOJA FÍSICA, O FORNECEDOR NÃO É OBRIGADO A DEVOLVER O DINHEIRO DO CONSUMIDOR EM CASO DE DESISTÊNCIA DE COMPRA, POIS O CDC ENTENDE QUE O CLIENTE PODE VER OU EXPERIMENTAR O PRODUTO ANTES DE FINALIZAR A AQUISIÇÃO.APARELHOS SEMINOVOS QUE VIER APRESENTAR DEFEITO DE FABRICA, TEMOS ATÉ 30 DIAS ÚTEIS PARA SOLUCIONAR O PROBLEMA.', 'PADRAO', '2023-10-11T03:03:00', '2026-02-04T10:51:00', 'patrickdio1994@outlook.com');
