VALUES ('1697208061353x525588429488259100', 'APPLE ERA', '45.666.827/0001-77', 'jm.colinski@gmail.com', '(45) 9 9948-3413', '@appleeraa', 'AVENIDA MARIPÁ', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1697208171833x848214421489900200/376661344_1012574433308827_3737143400995210468_n.jpg', NULL, 'Essencial', 'Mensal', '2025-07-17T07:11:00', '2025-05-19T10:11:00', NULL, 2, NULL, true, true, false, false, false, false, false, false, true, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, 'cus_000072873090', NULL, NULL, '1759220461982x422200843632327700', NULL, NULL, NULL, NULL, NULL, '[b]I.[/b] A garantia cobre os aparelhos lacrados/novos contra defeitos de fabricação durante um ano e cobre durante três meses os aparelhos seminovos, contado da data da compra pelo usuário final. [b]II.[/b] Aparelhos que apresentarem defeitos de fábrica (constatados por pericia técnica) em até sete dias corridos após a compra, a empresa se compromete em trocar o mesmo, por outro aparelho de mesmo modelo e qualidades, sem custo algum para o(a) cliente. [b]III.[/b] A garantia não abrange: [ml][ul][li indent=0 align=left]funcionamento, instalação e atualização de aplicativos, bem como o sistema operacional do aparelho;[/li][li indent=0 align=left]Qualquer mau funcionamento APÓS ATUALIZAÇÕES do sistema operacional ou aplicativos;[/li][li indent=0 align=left]Limpeza e conservação do aparelho;[/li][/ul][/ml][b]IV.[/b] Os atendimentos no que tange à garantia dos aparelhos, serão prestados na loja física da empresa, ficando desde já o cliente ciente, que é de sua responsabilidade levar e buscar o aparelho, no referido endereço, caso necessite de garantia.', 'PADRAO', '2023-10-13T11:41:00', '2026-01-09T10:05:00', 'jm.colinski@gmail.com');
INSERT INTO empresas (bubble_unique_id, nome, cnpj, email, telefone, instagram, endereco, logo_url, slug, plano, recorrencia, acesso_ate, ultimo_acesso, limite_usuarios, qtd_vendedores, usuario_adicional, ativo, cadastro_completo, primeiro_acesso, aguardando_aprovacao, beta, super_beta, novos_modelos, novas_cores, info_pagto_assinatura, assinatura_irregular, primeiro_pagto, adiciona_dias, fiscal_ativo, fiscal_cnpj, fiscal_ie, regime_tributario, certificado_ref, rf_fiscal_ref, addon_assistencia, addon_emp_fiscal, addon_os_planos, asaas_customer_id, assinatura_ref, api_key, project_ref, carteira_ref, engajamento_ref, fatura_url, configuracoes_gerais, crm_acesso_ate, termos, termo_empresa, id_visual, created_at, updated_at, created_by)
VALUES ('1697305742521x945397124907925500', 'AICITY', '50.128.614/0001-21', 'digitalcitybs@gmail.com', '(11) 9 6632-7281', '@applecity.bs', 'Rua Vergueiro 2253 - Vila Mariana', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1710105322262x129406750965563420/IMG_6547%202.PNG', NULL, 'Gerencial', 'Anual', '2026-11-04T12:45:00', '2026-02-04T08:44:00', NULL, 4, 17, true, true, false, false, false, false, true, true, true, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, 'cus_000066584607', 'cus_000063251720', NULL, NULL, '1759220461905x902725118254184700', '157', NULL, 'Informar motivo de cancelamento de Compra , Informar motivo de cancelamento do Atendimento', NULL, NULL, 'A AICITY fornece uma garantia SOMENTE para as peças com defeitos de fabricação e funcionamento.Fica estabelecido, para tanto, o prazo de 90 (Noventa) dias. A contagem deverá iniciar, a partir do recebimento do aparelho.No caso de problemas ou vício oculto, o aparelho deverá ser direcionado para loja física Apple City, onde ficará em análise pelo nosso técnico especializado no prazo de até 7 dias úteis, para assim dar a resposta do reparo ou troca do aparelho. O reparo ou troca terá o prazo de até 30 dias após a análise para execução do procedimento no aparelho ou troca conforme determinado por lei, pois trabalhamos com produtos de alta complexidade.A AiCITY é a única empresa que poderá realizar a abertura e quebra do lacre do produto, uma vez que se trata da empresa garantidora. Fica proibido a abertura do produto por qualquer uma empresa de assistência, sendo ou não autorizada do fabricante.Esclarecido que os produtos semi novos, podem ter peças internas trocadas antes do momento da venda.A política de garantia acima estabelecida, apenas realiza troca dos aparelhos defeituosos, pelo mesmo aparelho que deverá ser reparado ou em caso de troca, deverá ser por outro do mesmo modelo e categoria (seminovo) em perfeito estado de funcionamento.Caso o consumidor tenha interesse na troca do aparelho por outro modelo diferente do adquirido, o aparelho será reavaliado, aplicando para o mesmo a tabela diferenciada para abatimento de valores da AiCITY.Não será realizada a devolução dos valores, em nenhuma hipótese, uma vez que a lei determina este procedimento SOMENTE para compras realizadas virtualmente, o que não foi praticado neste caso, uma vez que o consumidor declara neste ato ter sido está uma compra presencial na loja.Não será possível a troca do produto, caso o mesmo apresente problema ou defeito após decorridos os 90 (Noventa) dias. A AiCITY recomenda a conservação do comprovante de compra e o número IMEl de seu produto, uma vez que a mesma não tem a obrigação de guardar o respectivo comprovante.O consumidor declara estar ciente de que os acessórios que acompanham o aparelho, trata-se de produto similar ao do fabricante da marca, porém possuem a mesma funcionalidade e não prejudicam a vida útil dos aparelhos.O consumidor tem ciência que o aparelho semi novo, pode ter sido ativado, haja vista que se tratam de aparelhos usados. O mesmo pode ter sido reparado e trocado peças para entregar em perfeito estado conforme o checklist de entrega do aparelho.Declara, ainda, o consumidor que no caso de troca de peça, o mesmo devera arcar com os custos, no caso de isenção e exclusão desta garantia.O consumidor declara que no ato da compra, conferiu a situação e apresentação do aparelho e imei, bem como declara que o mesmo não possui qualquer defeito, renunciando o direito de questionamento pré processual ou judicial.Para efeitos de TROCA não são considerados defeitos de fabricação:1) Defeitos ou danos resultantes do mau uso, como telas quebradas, rachadas, display manchado e entre outros problemas similares;2) Conserto realizado por outra assistência técnica dentro dos 90 (Noventa) dias;3) Produtos que tenham tido o lacre de segurança rompido, número de série removido, adulterado ou tomado ilegível;4) Danos por fluidos, como por exemplo, danos causados por contato com água.Todos os itens descritos acima anulam automaticamente a garantia prestada pela AiCITY.', 'PADRAO', '2023-10-14T14:49:00', '2026-02-04T08:44:00', 'digitalcitybs@gmail.com');
INSERT INTO empresas (bubble_unique_id, nome, cnpj, email, telefone, instagram, endereco, logo_url, slug, plano, recorrencia, acesso_ate, ultimo_acesso, limite_usuarios, qtd_vendedores, usuario_adicional, ativo, cadastro_completo, primeiro_acesso, aguardando_aprovacao, beta, super_beta, novos_modelos, novas_cores, info_pagto_assinatura, assinatura_irregular, primeiro_pagto, adiciona_dias, fiscal_ativo, fiscal_cnpj, fiscal_ie, regime_tributario, certificado_ref, rf_fiscal_ref, addon_assistencia, addon_emp_fiscal, addon_os_planos, asaas_customer_id, assinatura_ref, api_key, project_ref, carteira_ref, engajamento_ref, fatura_url, configuracoes_gerais, crm_acesso_ate, termos, termo_empresa, id_visual, created_at, updated_at, created_by)
VALUES ('1697478783886x858181469447127000', 'Florencell', '14.762.259/0018-4', 'lucasflorencio100@gmail.com', '(61) 9 9917-2634', '@florencell_cristalina', 'rua visconde de maua 1485 centro', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1697479170210x413425415484770300/WhatsApp%20Image%202023-10-16%20at%2014.59.06.jpeg', NULL, 'Essencial', 'Anual', '2026-11-11T15:16:00', '2026-01-29T10:19:00', NULL, 1, NULL, true, true, false, false, false, false, true, true, true, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, 'cus_000066280640', 'cus_000066280640', NULL, NULL, '1759220461808x226052549656250430', '71', NULL, NULL, NULL, NULL, 'I. A garantia cobre os aparelhos lacrados/novos contra defeitos de fabricação durante um ano(pela apple) e cobre durante três meses os aparelhos seminovos, contado da data da compra pelo usuário final. I I . Aparelhos que apresentarem defeitos de fábrica (constatados por pericia técnica) e mais sete dias corridos após a compra, a empresa se compromete em trocar o mesmo, por outro aparelho de mesmo modelo e qualidades, sem custo algum para o(a) cliente. III. A garantia não abrange funcionamento, instalação e atualização de aplicativos,bem como o sistema operacional do aparelho; Qualquer mau funcionamento APÓS ATUALIZAÇÕES do sistema operacional o aplicativos; Limpeza e conservação do aparelho. IV. Os atendimentos no que tange à garantia dos aparelhos, serão prestados na loja física da empresa, ficando desde já o cliente ciente, que é de sua responsabilidade levar e buscar o aparelho, no referido endereço, caso necessite de garantia. V. No ato da compra, o cliente declara que foi informado que o WhatsApp específicos/oficiais para tratativas sobre garantia dos aparelhos é o telefone no cabeçalho da nota.', 'PADRAO', '2023-10-16T14:53:00', '2026-01-29T10:19:00', 'lucasflorencio100@gmail.com');
