VALUES ('1698360225196x327933241506922500', 'iPhone Imports SG', '49.317.669/0001-09', 'iphoneimports.sg@gmail.com', '(34) 9 9640-6829', '@iphoneimports.sg', 'Rua Antonio José de Castro, 108, Centro, São Gotardo-MG, CEP 38.800-000', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1698932022002x997158596127784200/286897346_728714785004024_580745653157051060_n.jpg', NULL, 'Estratégia', 'Anual', '2026-11-06T11:52:00', '2026-02-04T09:50:00', NULL, 2, 1, true, true, false, false, false, false, true, true, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, 'cus_000071373646', 'cus_000071373646', NULL, NULL, '1759220461587x907345438697277700', '114', NULL, NULL, '2026-11-06T11:52:00', NULL, 'PARA APARELHOS NOVOS:  A IPHONEIMPORTS SG SE RESPONSABILIZA PELA SOLICITAÇÃO DA GARANTIA APPLE DE UM ANO EM CASO DE NECESSIDADE DO CLIENTE  PARA APARELHOS SEMINOVOS:  Fica automaticamente cancelada a GARANTIA LEGAL se vierem a ocorrer quaisquer das condições abaixo:  •Danos no aparelho provocados por: queda, batidas, descarga elétrica atmosférica (raio), inundação, desabamento, fogo, umidade, transpiração excessiva, exposição à luz solar, salinidade, exposição a temperatura excessivamente fria (geada), armazenamento inadequado, sinistro (roubo/furto), ligação à rede elétrica imprópria;  •Sinais de violações externas e internas, ou ainda, alterações da configuração do produto, que venham comprometer a integridade dos componentes originais;  •Se o CERTIFICADO DE GARANTIA do produto apresentarem adulterações e/ou rasuras;  •Se o NÚMERO DE SÉRIE ou ETIQUETAS forem removidos ou apresentarem adulterações e/ou rasuras, ou ainda, não forem coincidentes com a numeração da placa, acessórios, bateria, caixa, etc.', 'PADRAO', '2023-10-26T19:43:00', '2026-02-04T09:50:00', 'iphoneimports.sg@gmail.com');
