VALUES ('1698418202757x266611143946797060', 'IMEGACELL', '44.595.350/0001-13', 'imegacell2023@gmail.com', '(51) 9 8910-1000', '@imegacell', 'RUA DR LEGENDRE', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1698418692077x286824970281557950/IMEGA.jpeg', NULL, 'Inativo', NULL, '2023-11-03T11:50:00', NULL, NULL, 2, NULL, false, true, false, false, false, false, false, false, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '- GARANTIA DE 90 DIAS, EM QUALQUER REPARO UTILIZADO PEÇAS. SERVIÇOS QUE NÃO UTILIZAM PEÇAS (BANHO QUÍMICO, SOFTWARE, LIMPEZAS EM GERAL) NÃO POSSUEM GARANTIA. GARANTIA NÃO COBRE MAL USO OU QUEBRA. TELAS ARRANHADAS, MOLHADAS OU QUEBRADAS (NÃO POSSUEM GARANTIA). TELAS EXCLUSIVAMENTE DE IPHONE (POSSUEM 365 DIAS DE GARANTIA). GARANTIA EFETUADA EM UM PRAZO MÁXIMO DE 30 DIAS.', 'PADRAO', '2023-10-27T11:50:00', '2026-01-06T13:26:00', 'imegacell2023@gmail.com');
