VALUES ('1698874731569x982618352871276500', 'MidyStore', '33.612.473/0001-07', 'dyego_phernando@icloud.com', '(98) 9 8494-2609', 'midystorebr', 'Av. Rio Branco; 28B; CANTANHEDE/MA - CEP: 65.465-000', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1743108718044x551910094757702000/6654404f-302f-4dba-8d92-6295282f8fd8%202.JPG', NULL, 'Gerencial', 'Anual', '2026-05-21T18:14:00', '2026-02-02T19:43:00', NULL, 1, NULL, true, true, false, false, false, false, false, true, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, 'cus_000084401730', NULL, NULL, '1759220460825x447835099403597300', '39', NULL, NULL, NULL, NULL, '[center]                      TERMO DE GARANTIA[/center] [justify]Prezado Cliente,[/justify] [justify]Oferecemos garantia sobre o produto (mediante apresentação do termo de garantia), contra qualquer defeito de fabricação que o mesmo venha a apresentar no prazo de 6 meses de Garantia Legal a contar da data de emissão do Termo de Garantia.[/justify] [justify]A MidyStore declara a garantia nula ou sem efeito caso o produto tenha sofrido dano provocado por mau uso (queda, uso em desacordo, ou qualquer outra operação, etc.), fenômenos da natureza (infiltração, descarga atmosférica, etc.) ou por ter sido enviado para manutenção a qualquer assistência técnica que não seja a oferecida pela própria empresa. Os equipamentos somente serão recebidos com apresentação do Termo de Garantia e, realizados na sede MidyStore em Cantanhede MA, ou em local a ser de acordo de ambas as partes.[/justify] [justify]Também será considerada nula a garantia se o Termo de Garantia apresentar rasuras ou modificações.[/justify] [justify]Após o recebimento do produto, a MidyStore tem o prazo de até 10 dias úteis para reparar e/ou prestar manutenção e restituir os equipamentos.[/justify] [justify]São de responsabilidade do consumidor os riscos no transporte e despesas de ida e volta do equipamento à MidyStore em Cantanhede MA, ou em local a ser de acordo de ambas as partes.[/justify] [justify]Nos casos em que o produto não esteja mais disponível no portfólio da empresa e[/justify] [justify]apresente defeito dentro do prazo de garantia, serão tomadas as seguintes providências caso não haja reparo em até 10 dias úteis :[/justify] [justify]a) Substituição por outro com a mesma função dentro do prazo de 10 dias úteis.[/justify] [justify]b) Abatimento do valor na troca por um produto superior.[/justify] [center][/center]', 'PADRAO', '2023-11-01T18:39:00', '2026-02-02T19:43:00', 'dyego_phernando@icloud.com');
INSERT INTO empresas (bubble_unique_id, nome, cnpj, email, telefone, instagram, endereco, logo_url, slug, plano, recorrencia, acesso_ate, ultimo_acesso, limite_usuarios, qtd_vendedores, usuario_adicional, ativo, cadastro_completo, primeiro_acesso, aguardando_aprovacao, beta, super_beta, novos_modelos, novas_cores, info_pagto_assinatura, assinatura_irregular, primeiro_pagto, adiciona_dias, fiscal_ativo, fiscal_cnpj, fiscal_ie, regime_tributario, certificado_ref, rf_fiscal_ref, addon_assistencia, addon_emp_fiscal, addon_os_planos, asaas_customer_id, assinatura_ref, api_key, project_ref, carteira_ref, engajamento_ref, fatura_url, configuracoes_gerais, crm_acesso_ate, termos, termo_empresa, id_visual, created_at, updated_at, created_by)
VALUES ('1698976509444x414489448481816600', 'iTech - Brasil', '52.461.244/0001-75', 'dantasroberto.br@gmail.com', '(75) 9 9919-3851', '@itech_br', 'Avenida Getulio Vargas, 471, Feira de Santana - BA', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1700004163070x366242773219954050/Captura%20de%20Tela%202023-11-14%20%C3%A0s%2020.22.22.png', NULL, 'Essencial', 'Anual', '2025-11-18T11:00:00', '2025-11-27T10:29:00', NULL, NULL, NULL, true, true, false, false, false, false, false, true, true, true, false, true, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, 'cus_000071703728', NULL, NULL, '1759220460710x969356627839190800', '41', NULL, NULL, NULL, NULL, '[justify]Neste ato, o VENDEDOR transfere a posse do aparelho ao COMPRADOR, que passa ser responsável, Civil e Criminal, por todos os atos praticados, com o mesmo, a partir deste dia e hora.[/justify]  [justify]Neste ato o COMPRADOR, retira o aparelho celular adquirido e toma ciência do TERMO DE GARANTIA, valido pelo prazo de 90 (noventa) dias. Este termo estabelece prazos, normas e condições da garantia. O presente termo, somente estabelece normas, dentro do prazo da garantia legal, nos moldes do artigo 26° do Código de Defesa de Consumidor. Isto não é uma garantia contratual adicional.[/justify]  [justify]Todo e qualquer defeito que o produto venha a apresentar, dentro do prazo de garantia, deverá ser comunicado ao vendedor, no máximo em 24 (vinte e quatro) horas após ter sido detectado, devendo ser feito por escrito e de forma inequívoca.[/justify]  [justify]Para que sejam efetuados os reparos necessários, o Comprador deverá enviar o aparelho celular ao Vendedor, ou para a oficina que este indicar, por sua conta e risco.[/justify] [justify][/justify] [justify]O prazo máximo para uma resposta acerca da aprovação ou não do reparo ou troca do aparelho é de 7 (sete) dias úteis. Sendo aprovado, o VENDEDOR poderá, de forma não obrigatória, fornecer um aparelho reserva ao COMPRADOR enquanto o reparo estiver sendo realizado, e o mesmo deverá ser devolvido nas mesmas condições que lhe foi entregue.[/justify] [justify][/justify] [justify]O COMPRADOR perderá totalmente a garantia do aparelho celular, caso seja constatada qualquer uma das ocorrências abaixo relacionadas:[/justify] [justify][/justify] [justify]· O aparelho tenha sido submetido ao uso de forma inadequada, imprudente, negligente ou danificado por acidente, sendo possível constatar marcas de mau uso.[/justify] [justify]· Tenha sido aberto, exposto à água, ou alteradas suas características originais de fábrica.[/justify] [justify]· Tenha sido reparado em oficina diversa, sem o conhecimento e consentimento expresso do vendedor ou tenha seu selo de garantia rompido.[/justify] [justify][/justify] [justify][/justify] [justify][/justify] [justify]Neste ato tomo ciência do teor do referido termo, que me foi lido e explicado de forma clara e objetiva, concordando com tudo, e ainda, declaro que me foi entregue uma cópia, do referido termo, impressa ou digital. Termo elaborado em 2 (duas) laudas.[/justify]', 'PADRAO', '2023-11-02T22:55:00', '2026-01-09T10:05:00', 'dantasroberto.br@gmail.com');
