VALUES ('1699195764462x350044275601309700', 'JRINFOCELL', '53.897.619/0001-07', 'jrinfocell.com@gmail.com', '(87) 9 9662-4384', '@jrinfocellfilial', 'RUA CECILIA DELGADO 125, CENTRO, PETROLÂNDIA-PE, CEP 56460-000', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1699196373072x362956028030807940/favicon%202.png', NULL, 'Estratégia', 'Anual', '2026-06-23T17:44:00', '2026-02-04T08:10:00', NULL, 2, 2, true, true, false, false, false, false, true, true, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, 'cus_000071847962', NULL, NULL, '1759220460521x901498082750490400', '126', NULL, NULL, '2026-06-23T17:44:00', NULL, '[justify][b]1) O PRODUTO (ACESSÓRIO) POSSUI A GARANTIA LEGAL DE 90 (NOVENTA) dias, que está de acordo com o artigo 26 inciso II do Código de Defesa do Consumidor.[/b][/justify]', 'PADRAO', '2023-11-05T11:49:00', '2026-02-04T08:10:00', 'jrinfocell.com@gmail.com');
