VALUES ('1700147605447x609780292304764900', 'Meu iPhone dos Sonhos', '58.523.429/0001-43', 'meuiphonedossonhos@gmail.com', '(13) 9 9684-0175', '@meuiphonedossonhos', 'Rua Benjamin Constant, 61 São Vicente/SP 11310-500', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1700148307524x683788532866695600/IMG_4313.jpg', NULL, 'Gerencial', 'Mensal', '2026-02-22T08:14:00', '2026-02-04T02:24:00', NULL, 3, NULL, true, true, false, false, false, false, true, true, true, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, 'cus_000073317974', NULL, NULL, '1759220460112x758528539487781400', '134', NULL, NULL, '2025-08-01T10:00:00', NULL, '[b]O rompimento do lacre de garantia, localizado na parte inferior do aparelho, resultará na perda imediata da garantia. Portanto, é crucial não remover esse lacre, pois ele é o garantidor da proteção de seu dispositivo.[/b] A garantia para produtos seminovos é válida por 6 meses a partir da data de compra e é oferecida pela empresa sob os seguintes termos: [ml][ol][li indent=0 align=left][color=var(--tw-prose-bold)]Reparo Gratuito e Reposição de Peças[/color]: Caso o aparelho apresente defeito, realizaremos o reparo gratuito e substituição de peças conforme nossa avaliação técnica, dentro de um prazo de 2 semanas a partir da devolução do dispositivo.[/li][li indent=0 align=left][color=var(--tw-prose-bold)]Nota de Compra Obrigatória[/color]: Para que nosso serviço autorizado possa receber o produto para garantia, é imperativo que ele esteja acompanhado da nota de compra.[/li][li indent=0 align=left][color=var(--tw-prose-bold)]Restrições de Ativação[/color]: Não podemos aceitar aparelhos bloqueados por contas (Google, iCloud), pois isso impossibilita o manuseio do dispositivo.[/li][li indent=0 align=left][color=var(--tw-prose-bold)]Cancelamento da Garantia Legal[/color]: A garantia legal será automaticamente cancelada se ocorrerem quaisquer das seguintes condições:[/li][/ol][/ml][ml][ul][ul data=1][li indent=1 align=left]Danos ao aparelho causados por queda, batidas, descargas elétricas atmosféricas (raios), inundação, desabamento, incêndio, umidade excessiva, exposição solar prolongada, contato com salinidade, temperaturas extremamente frias (geada), armazenamento inadequado, sinistro (roubo/furto) ou conexão a rede elétrica imprópria.[/li][li indent=1 align=left]Adulterações ou rasuras no lacre de garantia ou no comprovante de compra do produto.[/li][/ul][/ul][/ml][b]A garantia de 1 ano para aparelhos lacrados é de responsabilidade da Apple. Portanto, qualquer dispositivo lacrado conta com essa garantia estendida. Se tiver mais perguntas ou necessitar de esclarecimentos adicionais, estamos à disposição para ajudar.[/b]', 'PADRAO', '2023-11-16T12:13:00', '2026-02-04T02:24:00', 'meuiphonedossonhos@gmail.com');
INSERT INTO empresas (bubble_unique_id, nome, cnpj, email, telefone, instagram, endereco, logo_url, slug, plano, recorrencia, acesso_ate, ultimo_acesso, limite_usuarios, qtd_vendedores, usuario_adicional, ativo, cadastro_completo, primeiro_acesso, aguardando_aprovacao, beta, super_beta, novos_modelos, novas_cores, info_pagto_assinatura, assinatura_irregular, primeiro_pagto, adiciona_dias, fiscal_ativo, fiscal_cnpj, fiscal_ie, regime_tributario, certificado_ref, rf_fiscal_ref, addon_assistencia, addon_emp_fiscal, addon_os_planos, asaas_customer_id, assinatura_ref, api_key, project_ref, carteira_ref, engajamento_ref, fatura_url, configuracoes_gerais, crm_acesso_ate, termos, termo_empresa, id_visual, created_at, updated_at, created_by)
VALUES ('1700155487829x736626600283996200', 'IHud Store', '46.997.373/0001-80', 'hudsonlougas1@gmail.com', '(98) 9 9139-4178', '@ihudstore', 'Avenida 31 De Março', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1700168862954x119082720040714960/2.png', NULL, 'Essencial', 'Mensal', '2026-03-01T18:48:00', '2026-02-04T08:33:00', NULL, 1, NULL, true, true, false, false, false, false, true, true, true, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, 'cus_000072861817', 'cus_000072861817', NULL, NULL, '1759220459991x843706476874260400', '112', NULL, NULL, '2025-08-29T10:00:00', NULL, '[ml][ul][li indent=0 align=center][b][highlight=transparent]DO OBJETO[/highlight][/b][/li][/ul][/ml] [justify][b][highlight=transparent]Cláusula 1ª:[/highlight][/b][highlight=transparent] O comprador está adquirindo o produto descrito acima, em plenas condições de uso, devidamente testado, concordando com todas as características e estado do item, inexistindo qualquer defeito, mediante valor e forma de pagamento ajustado entre as partes.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 2ª:[/highlight][/b][highlight=transparent] Por tratar-se de um aparelho seminovo, todas as informações e características do produto foram repassadas pelo vendedor no ato da compra, mas também poderão ser extraídas diretamente no site do fabricante, sendo esse: https://support.apple.com/pt-br/guide/iphone/welcome/ios, ou até mesmo através do revendedor, sendo esse: https://www.iplace.com.br/iplace/iphone/cat1300011[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 3ª:[/highlight][/b][highlight=transparent] A iHud Store não garante que o item adquirido nunca foi aberto para reparo ou substituição de peça, estando o comprador ciente de tal condição.[/highlight][/justify] [ml][ul][li indent=0 align=center][b][highlight=transparent]DAS OBRIGAÇÕES DO COMPRADOR[/highlight][/b][/li][/ul][/ml] [justify][b][highlight=transparent]Cláusula 4ª:[/highlight][/b][highlight=transparent] Trata-se de um aparelho seminovo, desta forma, a iHud Store orienta o comprador a não expor o celular a líquidos ou poeira, tendo em vista que a própria fabricante do aparelho aduz que a resistência contra respingos, água e poeira não é uma condição permanente e pode diminuir com o tempo, gerando assim maior durabilidade do celular.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 5ª:[/highlight][/b][highlight=transparent] O consumidor se compromete a utilizar o aparelho celular com proteção adequada, itens originais do fabricante ou homologados, bem como a instalar apenas aplicativos fornecidos no sistema da fabricante (Apple Story).[/highlight][/justify] [ml][ul][li indent=0 align=center][b][highlight=transparent]DAS OBRIGAÇÕES DA VENDEDORA[/highlight][/b][/li][/ul][/ml] [justify][b][highlight=transparent]Cláusula 6ª:[/highlight][/b][highlight=transparent] Na hipótese de o produto apresentar falha ou vício de fabricação dentro do prazo de garantia, o consumidor deverá procurar imediatamente a iHud Store, não sendo permitido que terceiros avaliem ou reparem o produto, sob pena do comprador ser responsável por tal ato, eximindo a iHud Store do dever de reparar, além da perda da garantia.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 7ª: [/highlight][/b][highlight=transparent]A iHud Store terá o prazo de 15 dias para reparar o produto em questão, contados a partir do momento em que o produto for recebido pela mesma.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 8ª: [/highlight][/b][highlight=transparent]Caso não seja possível efetuar o reparo dentro do prazo de 30 dias e o cliente opte pela troca do produto, deverá ser analisado a disponibilidade do estoque de seminovos, não podendo o consumidor exigir um outro aparelho com a mesma cor e saúde da bateria equivalente, tendo em vista tratar-se de um produto seminovo, garantindo a iHud Store que será entregue um produto em plenas condições de uso, mesmo modelo e capacidade de armazenamento, em última instância devolveremos o dinheiro do aparelho, caso não seja possível a realização de nenhuma das alternativas realizadas acima, e será devolvido somente o valor do aparelho, não está incluso acessórios como capa e película, somente o valor do aparelho.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 9ª:[/highlight][/b][highlight=transparent] Caso seja necessário o reparo e formatação do aparelho celular, é responsabilidade do comprador manter atualizado o backup se assim entender, não sendo a iHud Store responsável pela perda dos dados, contatos, imagens, vídeos etc.[/highlight][/justify] [ml][ul][li indent=0 align=center][b][highlight=transparent]DA GARANTIA DO PRODUTO[/highlight][/b][/li][/ul][/ml] [justify][b][highlight=transparent]Cláusula 10ª:[/highlight][/b][highlight=transparent] A garantia será de _______ dias, contados do recebimento ou retirada em loja do produto, respeitando o Código de Defesa do Consumidor e será prestada pela própria[Loja] ou terceiros indicados pela mesma.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 11ª:[/highlight][/b][highlight=transparent] A garantia do produto cessará nos seguintes casos: [/highlight][/justify] [ml][ul][li indent=0 align=justify][highlight=transparent]Não sejam seguidas as recomendações de conservação e uso contidas no manual de instrução do próprio fabricante;[/highlight][/li][li indent=0 align=justify][highlight=transparent]Seja constatado defeito no produto decorrente de negligência, imperícia ou mau uso pelo próprio consumidor;[/highlight][/li][li indent=0 align=justify][highlight=transparent]O produto seja examinado, adulterado ou consertado por terceiros sem autorização da iHud Store;[/highlight][/li][li indent=0 align=justify][highlight=transparent]Houver remoção e/ou alteração do número de série do equipamento ou de quaisquer dos seus componentes internos;[/highlight][/li][li indent=0 align=justify][highlight=transparent]O produto tiver o lacre/selo violado, quando houver;[/highlight][/li][li indent=0 align=justify][highlight=transparent]Caso ocorra a utilização de hardware, peça ou componente não original ou homologadas;[/highlight][/li][li indent=0 align=justify][highlight=transparent]Caso ocorra alteração/modificação do software ou sistema operacional original do produto;[/highlight][/li][li indent=0 align=justify][highlight=transparent]Caso seja constatado danos físicos ou químicos internos ou externos ao produto decorrente de choque, queda, ato e efeito causado por ação de agentes da natureza, líquidos, oxidação, oscilações de tensão elétrica, exposição excessiva ao calor ou pressão excessiva na tela;[/highlight][/li][li indent=0 align=justify][highlight=transparent]Quando for constatado que o defeito foi causado por equipamento a ele conectado.[/highlight][/li][li indent=0 align=justify][highlight=transparent]Desgaste natural em razão do envelhecimento do produto;[/highlight][/li][li indent=0 align=justify][highlight=transparent]Danos estéticos, incluindo arranhões, amassados e rachaduras no produto;[/highlight][/li][/ul][/ml][justify][b][highlight=transparent]Cláusula 12ª:[/highlight][/b][highlight=transparent] Caso a iHud Store receba o aparelho celular para exercício da garantia e constate uma das ilegalidades supracitadas, o comprador será comunicado imediatamente sobre a não cobertura do reparo de forma gratuita.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 13ª:[/highlight][/b][highlight=transparent] Após a constatação e comunicação do comprador, o aparelho ficará disponível para retirada em loja mediante agendamento.[/highlight][/justify] [ml][ul][li indent=0 align=center][b][highlight=transparent]DISPOSIÇÕES GERAIS[/highlight][/b][/li][/ul][/ml] [justify][b][highlight=transparent]Cláusula 15ª:[/highlight][/b][highlight=transparent] Ao assinar o presente contrato, o comprador concorda que a iHud Store poderá utilizar suas imagens sejam elas mediante vídeo ou fotografia, nas redes sociais da loja, para fins comerciais e de marketing.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 16ª:[/highlight][/b][highlight=transparent] A cessão dos direitos de uso e reprodução da imagem do comprador, não gera nenhum ônus lucrativo ao cedente, ocorrendo de forma gratuita e voluntária.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 17ª:[/highlight][/b][highlight=transparent] O comprador concorda que a única empresa participante da negociação deste produto é a iHud Store, registrada no CNPJ informado anteriormente.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 18ª:[/highlight][/b][highlight=transparent] A garantia elencada no presente contrato deverá ser exercida exclusivamente pelo comprador qualificado neste ato, o qual deverá apresentar o presente termo ao acionar a garantia.[/highlight][/justify]', 'PADRAO', '2023-11-16T14:24:00', '2026-02-04T08:33:00', 'hudsonlougas1@gmail.com');
INSERT INTO empresas (bubble_unique_id, nome, cnpj, email, telefone, instagram, endereco, logo_url, slug, plano, recorrencia, acesso_ate, ultimo_acesso, limite_usuarios, qtd_vendedores, usuario_adicional, ativo, cadastro_completo, primeiro_acesso, aguardando_aprovacao, beta, super_beta, novos_modelos, novas_cores, info_pagto_assinatura, assinatura_irregular, primeiro_pagto, adiciona_dias, fiscal_ativo, fiscal_cnpj, fiscal_ie, regime_tributario, certificado_ref, rf_fiscal_ref, addon_assistencia, addon_emp_fiscal, addon_os_planos, asaas_customer_id, assinatura_ref, api_key, project_ref, carteira_ref, engajamento_ref, fatura_url, configuracoes_gerais, crm_acesso_ate, termos, termo_empresa, id_visual, created_at, updated_at, created_by)
VALUES ('1700167992712x907487921963794400', 'Lucstore imports (antigo)', '395.402.098-03', 'luquinha_lu@hotmail.com', '(12) 9 9159-4503', 'LUCSTOREIMPORTS', 'RUA DR. ORLANDO FEIRABEND FILHO , 230 , SAO JOSE DOS CAMPOS/SP - CEP 12246-190', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1700170665823x660788483955287200/IMG_1252.jpeg', NULL, 'Gerencial', 'Mensal', '2024-02-15T23:59:00', NULL, NULL, 3, NULL, true, true, false, false, false, false, false, false, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, 'cus_000075958073', 'cus_000075958073', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ABRANGÊNCIA: A garantia é oferecida exclusivamente aos produtos e serviços relacionados ao aparelho identificado pelo número de IMEI abaixo discriminado. A garantia cobre defeitos de fabricação e montagem no componente substituído. Desde que a análise técnico tenha revelado a existência de vícios de qualidade passíveis de enquadramento neste termo. NÃO ESTÃO INCLUSOS NESTA GARANTIA ALGUNS ACESSÓRIOS E TODAS AS PARTES EXTERNAS DO APARELHO TAIS COMO: Lentes, antenas, carcaças, capas, cases, teclas, teclados e botões laterais se houver, tampas, películas protetoras, cabos de dados, fone de ouvido, cartão de memória, pen drive e suportes. E ainda: LENTE TOUCHSCREEN QUE APRESENTEM MAU USO, TRINCADOS OU QUEBRADOS, RISCADOS, MANCHADOS, DESCOLADOS E COM CABO FLEX ROMPIDO. A GARANTIA É CANCELADA AUTOMATICAMENTE NOS SEGUINTES CASOS: i. Quedas; ii. Esmagamentos; iii. Sobrecarga elétrica; iv. Exposição do aparelho a altas temperaturas; v. Umidade ou líquidos; vi. Exposição do aparelho a poeira, pó e\\o limalha de metais; vii. Mau uso do aparelho; viii. Instalações e modificações no seu sistema operacional; ix. Trincados ou quebrados (mesmo internos); x. Manchados; xi. Descolados; xii. Com cabo flex rompido; xiii. Abertura do equipamento ou tentativa de conserto deste por terceiros que não sejam os técnicos; xiv. Violação do selo\\lacre de garantia colocado pela nossa loja.   Essa garantia ficará automaticamente cancelada se os equipamentos vierem a sofrer reparos por pessoas não autorizadas, receber maus tratos ou sofrer danos decorrentes de acidentes, quedas, variações de tensão elétrica e sobrecarga acima do especificado, ou qualquer ocorrência imprevisível, decorrentes de má utilização dos equipamentos por parte do Cliente.   Essa garantia cobre somente os defeitos de funcionamento das peças e componentes dos equipamentos descritos nas condições normais de uso – de acordo com as instruções dos manuais de operação que acompanham os mesmos, e que são fornecidos pelos fabricantes.   Vale lembrar que: 1) A GARANTIA DE 180 (CENTO E OITENTA ) dias para SEMI NOVOS e 365 ( trezentos e sessenta e cinto)dias para aparelhos LACRADOS de acordo com o artigo 26 inciso II do código de defesa do consumidor; 2) Funcionamento, instalação e atualização de aplicativos, bem como o sistema operacional do aparelho NÃO FAZEM parte desta garantia; 3) Limpeza e conservação do aparelho NÃO FAZEM parte desta garantia; 4) A não apresentação de documento (este termo) que comprove o serviço INVÁLIDA a garantia; 5) Qualquer mal funcionamento APÓS ATUALIZAÇÕES do sistema operacional, ATUALIZAÇÕES INDEVIDAS ou na tentativa de TROCA DE SISTEMA ou na INSTALAÇAO e/ou DESINSTALAÇÃO de aplicativos NÃO FAZEM PARTE DESSA GARANTIA e eximem de responsabilidade o vendedor; 6) A GARANTIA é válida somente para o item ou serviço descrito neste termo de garantia, NÃO ABRANGENDO OUTRAS PARTES e respeitando as condições aqui descritas; 7) Ou qualquer tipo de dano que possa surgir decorrente a mal uso.     Confirmo que li este termo de garantia, fui orientado sobre o seu conteúdo e que testei o aparelho, e este se encontra em perfeito estado estético e de funcionamento no ato de sua retirada, não havendo nada a reclamar nem qualquer vicio.', 'PADRAO', '2023-11-16T17:53:00', '2026-01-09T10:05:00', 'luquinha_lu@hotmail.com');
INSERT INTO empresas (bubble_unique_id, nome, cnpj, email, telefone, instagram, endereco, logo_url, slug, plano, recorrencia, acesso_ate, ultimo_acesso, limite_usuarios, qtd_vendedores, usuario_adicional, ativo, cadastro_completo, primeiro_acesso, aguardando_aprovacao, beta, super_beta, novos_modelos, novas_cores, info_pagto_assinatura, assinatura_irregular, primeiro_pagto, adiciona_dias, fiscal_ativo, fiscal_cnpj, fiscal_ie, regime_tributario, certificado_ref, rf_fiscal_ref, addon_assistencia, addon_emp_fiscal, addon_os_planos, asaas_customer_id, assinatura_ref, api_key, project_ref, carteira_ref, engajamento_ref, fatura_url, configuracoes_gerais, crm_acesso_ate, termos, termo_empresa, id_visual, created_at, updated_at, created_by)
VALUES ('1700174312007x963533538929147900', 'FantiStore', '21.797.644/0001-22', 'arthur_fanti@hotmail.com', '(17) 9 8121-3966', '@fantistore01', 'rua 15 de novembro', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1700174936878x509379806091693000/logo.png', NULL, 'Gerencial', 'Anual', '2025-11-27T10:10:00', '2025-10-07T08:52:00', NULL, 2, NULL, true, true, false, false, false, false, false, false, true, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, 'cus_000073162850', NULL, NULL, '1759220459906x494760428352504640', '1', NULL, NULL, NULL, NULL, 'TERMOS DE GARANTIA FANTISTORE CONFORME O CÓDIGO DE DEFESA DO CONSUMIDOR:-Seu iPhone possui garantia de 6 meses após a data da compra;-A garantia cobre apenas defeitos de fábrica aparelho como: mau desempenho da bateria, reiniciar ou qualquer questão que não se enquadra como dano acidental;-Seu novo iPhone não poderá ser aberto por ninguém além do nosso técnico especializado. Caso isso ocorra, seu iPhone perderá a garantia conosco;-A garantia não danos acidentais, como QUEDA, QUEBRA ou MOLHADO. A partir do momento que nosso técnico especialista detectar quaisquer um desses danos acima citados, o aparelho perderá a garantia pela loja.-A FANTISTORE efetua rigorosos testes para prezar sempre pela qualidade de seus produtos, portanto, não trabalhamos com iPhones que já entraram em contato com líquido, pois, isso diminui a vida útil do aparelho. Sendo assim, não nos responsabilizamos por aparelhos que estiverem MOLHADO a partir da data da compra do produto e, o mesmo perderá a garantia pela nossa loja caso isso aconteça.-Para dar entrada com o iPhone na garantia você precisará vir até nossa loja física com o aparelho e, relatar o o corrido para nosso time responsável pelo suporte ao cliente;-Possuímos o prazo de até 5 dias úteis para a entrega do aparelho consertado.-Possuímos um técnico especializado em produtos Apple, portanto, caso precise trocar alguma peça do iPhone que estiver na garantia, o técnico fará a substituição da peça. Essa peça, substituída poderá ser semi genuína com garantia de 6 meses a partir da data da troca;-Caso o aparelho não possua conserto, forneceremos outro aparelho do mesmo modelo (podendo haver alteração da cor), dependendo da disponibilidade do nosso estoque. Se acontecer de não possuirmos o modelo específico no estoque, devolveremos o valor pago -Kit carregador: -Não nos responsabilizamos por problemas causado pelo uso de carregadores (CI de carga queimado ou danificado, problemas com desempenho da bateria ou bateria inchada) que não tenham sido adquirido conosco, por não termos ciência da procedência e qualidade desse produto.', 'PADRAO', '2023-11-16T19:38:00', '2026-01-09T10:05:00', 'arthur_fanti@hotmail.com');
INSERT INTO empresas (bubble_unique_id, nome, cnpj, email, telefone, instagram, endereco, logo_url, slug, plano, recorrencia, acesso_ate, ultimo_acesso, limite_usuarios, qtd_vendedores, usuario_adicional, ativo, cadastro_completo, primeiro_acesso, aguardando_aprovacao, beta, super_beta, novos_modelos, novas_cores, info_pagto_assinatura, assinatura_irregular, primeiro_pagto, adiciona_dias, fiscal_ativo, fiscal_cnpj, fiscal_ie, regime_tributario, certificado_ref, rf_fiscal_ref, addon_assistencia, addon_emp_fiscal, addon_os_planos, asaas_customer_id, assinatura_ref, api_key, project_ref, carteira_ref, engajamento_ref, fatura_url, configuracoes_gerais, crm_acesso_ate, termos, termo_empresa, id_visual, created_at, updated_at, created_by)
VALUES ('1700183137699x230704136094220300', 'All Cel', '37.683.434/0001-43', 'karinasouza90900@gmail.com', '(35) 9 9923-2321', 'all_cel1', 'rua jasmin 34', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1700188266879x428405961942227600/Logo_No_BG%202.png', NULL, 'Inativo', NULL, '2023-11-23T22:05:00', NULL, NULL, 2, NULL, false, true, false, false, false, false, false, false, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '[ml][ul][li indent=0 align=center][b][highlight=transparent]DO OBJETO[/highlight][/b][/li][/ul][/ml] [justify][b][highlight=transparent]Cláusula 1ª:[/highlight][/b][highlight=transparent] O comprador está adquirindo o produto descrito acima, em plenas condições de uso, devidamente testado, concordando com todas as características e estado do item, inexistindo qualquer defeito, mediante valor e forma de pagamento ajustado entre as partes.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 2ª:[/highlight][/b][highlight=transparent] Por tratar-se de um aparelho seminovo, todas as informações e características do produto foram repassadas pelo vendedor no ato da compra, mas também poderão ser extraídas diretamente no site do fabricante, sendo esse: https://support.apple.com/pt-br/guide/iphone/welcome/ios[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 3ª:[/highlight][/b][highlight=transparent] A[Loja] não garante que o item adquirido nunca foi aberto para reparo ou substituição de peça, estando o comprador ciente de tal condição.[/highlight][/justify] [justify][/justify] [ml][ul][li indent=0 align=center][b][highlight=transparent]DAS OBRIGAÇÕES DO COMPRADOR[/highlight][/b][/li][/ul][/ml] [justify][b][highlight=transparent]Cláusula 4ª:[/highlight][/b][highlight=transparent] Trata-se de um aparelho seminovo, desta forma, a[Loja] orienta o comprador a não expor o celular a líquidos ou poeira, tendo em vista que a própria fabricante do aparelho aduz que a resistência contra respingos, água e poeira não é uma condição permanente e pode diminuir com o tempo, gerando assim maior durabilidade do celular.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 5ª:[/highlight][/b][highlight=transparent] O consumidor se compromete a utilizar o aparelho celular com proteção adequada, itens originais do fabricante ou homologados, bem como a instalar apenas aplicativos fornecidos no sistema da fabricante (Apple Story).[/highlight][/justify] [justify][/justify] [ml][ul][li indent=0 align=center][b][highlight=transparent]DAS OBRIGAÇÕES DA VENDEDORA[/highlight][/b][/li][/ul][/ml] [justify][b][highlight=transparent]Cláusula 6ª:[/highlight][/b][highlight=transparent] Na hipótese de o produto apresentar falha ou vício de fabricação dentro do prazo de garantia, o consumidor deverá procurar imediatamente a[Loja], não sendo permitido que terceiros avaliem ou reparem o produto, sob pena do comprador ser responsável por tal ato, eximindo a[Loja] do dever de reparar, além da perda da garantia.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 7ª: [/highlight][/b][highlight=transparent]A[Loja] terá o prazo de 30 dias para reparar o produto em questão, contados a partir do momento em que o produto for recebido pela mesma.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 8ª: [/highlight][/b][highlight=transparent]Caso não seja possível efetuar o reparo dentro do prazo de 30 dias e o cliente opte pela troca do produto, deverá ser analisado a disponibilidade do estoque de seminovos, não podendo o consumidor exigir um outro aparelho com a mesma cor e saúde da bateria equivalente, tendo em vista tratar-se de um produto seminovo, garantindo a[Loja] que será entregue um produto em plenas condições de uso, mesmo modelo e capacidade de armazenamento.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 9ª:[/highlight][/b][highlight=transparent] Caso seja necessário o reparo e formatação do aparelho celular, é responsabilidade do comprador manter atualizado o backup se assim entender, não sendo a[Loja] responsável pela perda dos dados, contatos, imagens, vídeos etc.[/highlight][/justify] [justify][/justify] [ml][ul][li indent=0 align=center][b][highlight=transparent]DA GARANTIA DO PRODUTO[/highlight][/b][/li][/ul][/ml] [justify][b][highlight=transparent]Cláusula 10ª:[/highlight][/b][highlight=transparent] A garantia será de 90 dias, contados do recebimento ou retirada em loja do produto, respeitando o Código de Defesa do Consumidor e será prestada pela própria[Loja] ou terceiros indicados pela mesma.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 11ª:[/highlight][/b][highlight=transparent] A garantia do produto cessará nos seguintes casos: [/highlight][/justify] [justify][/justify] [ml][ul][li indent=0 align=justify][highlight=transparent]Não sejam seguidas as recomendações de conservação e uso contidas no manual de instrução do próprio fabricante;[/highlight][/li][li indent=0 align=justify][highlight=transparent]Seja constatado defeito no produto decorrente de negligência, imperícia ou mau uso pelo próprio consumidor;[/highlight][/li][li indent=0 align=justify][highlight=transparent]O produto seja examinado, adulterado ou consertado por terceiros sem autorização da[Loja];[/highlight][/li][li indent=0 align=justify][highlight=transparent]Houver remoção e/ou alteração do número de série do equipamento ou de quaisquer dos seus componentes internos;[/highlight][/li][li indent=0 align=justify][highlight=transparent]O produto tiver o lacre/selo violado, quando houver;[/highlight][/li][li indent=0 align=justify][highlight=transparent]Caso ocorra a utilização  de hardware, peça ou componente não original ou homologadas;[/highlight][/li][li indent=0 align=justify][highlight=transparent]Caso ocorra alteração/modificação do software ou sistema operacional original do produto;[/highlight][/li][li indent=0 align=justify][highlight=transparent]Caso seja constatado danos físicos ou químicos internos ou externos ao produto decorrente de choque, queda,  ato e efeito causado por ação de agentes da natureza, líquidos, oxidação, oscilações de tensão elétrica, exposição excessiva ao calor ou pressão excessiva na tela;[/highlight][/li][li indent=0 align=justify][highlight=transparent]Quando for constatado que o defeito foi causado por equipamento a ele conectado.[/highlight][/li][li indent=0 align=justify][highlight=transparent]Desgaste natural em razão do envelhecimento do produto;[/highlight][/li][li indent=0 align=justify][highlight=transparent]Danos estéticos, incluindo arranhões, amassados e rachaduras no produto;[/highlight][/li][/ul][/ml][justify][b][highlight=transparent]Cláusula 12ª:[/highlight][/b][highlight=transparent] Caso a[Loja] receba o aparelho celular para exercício da garantia e constate uma das ilegalidades supracitadas, o comprador será comunicado imediatamente sobre a não cobertura do reparo de forma gratuita.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 13ª:[/highlight][/b][highlight=transparent] Após a constatação e comunicação do comprador, o aparelho ficará disponível para retirada em loja mediante agendamento.[/highlight][/justify] [justify][/justify] [justify][b][highlight=transparent]﻿DISPOSIÇÕES GERAIS[/highlight][/b][/justify]  [justify][b][highlight=transparent]Cláusula 15ª:[/highlight][/b][highlight=transparent] Ao assinar o presente contrato, o comprador concorda que a[Loja] poderá utilizar suas imagens sejam elas mediante vídeo ou fotografia, nas redes sociais da loja, para fins comerciais e de marketing.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 16ª:[/highlight][/b][highlight=transparent] A cessão dos direitos de uso e reprodução da imagem do comprador, não gera nenhum ônus lucrativo ao cedente, ocorrendo de forma gratuita e voluntária.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 17ª:[/highlight][/b][highlight=transparent] O comprador concorda que a única empresa participante da negociação deste produto é a[Loja], registrada no CNPJ informado anteriormente.[/highlight][/justify] [justify][b][highlight=transparent]Cláusula 18ª:[/highlight][/b][highlight=transparent] A garantia elencada no presente contrato deverá ser exercida exclusivamente pelo comprador qualificado neste ato, o qual deverá apresentar o presente termo ao acionar a garantia.[/highlight][/justify]    [b][highlight=transparent]______________________[/highlight][/b] [b][highlight=transparent]Ciente[/highlight][/b]', 'PADRAO', '2023-11-16T22:05:00', '2026-01-06T13:26:00', 'karinasouza90900@gmail.com');
