VALUES ('1704748864213x526828948380188700', 'CARVALHO STORE', '51.209.452/0001-19', 'rafle.crf@hotmail.com', '(73) 9 8197-1515', '@carvalhostore73', 'Rua pedro telles cancela,45,Porto Seguro - CEP45810-000', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1706142028774x820918776911206300/Carvalho%20Store%20png%20.png', NULL, 'Essencial', 'Mensal', '2024-09-24T08:43:00', NULL, NULL, 3, NULL, true, true, false, false, false, false, false, false, true, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, 'cus_000077210331', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Cobrimos qualquer defeito de fabricação que o celular venha apresentar no prazo de 90 dias, inicia-se a contagem do prazo decadencial a partir da entrega efetiva do produto Garantia que não cobrimos: Em ocasião de quedas, esmagamentos, sobrecarga elétrica; exposição do aparelho a alta temperatura, umidade ou líquidos; exposição a poeira, ou ainda quando constatado o mau uso do aparelho, instalações, modificações ou atualizações no sistema operacional; abertura do equipamento ou tentativa de concerto por terceiros que não sejam os técnicos parceiros de Carvalho Store, mesmo que para realização de outros serviços. Bem como: lente touchscreen que apresenta mau uso, trincados, riscados ou manchados.', 'PADRAO', '2024-01-08T18:21:00', '2026-01-09T10:05:00', 'rafle.crf@hotmail.com');
