VALUES ('1708624662794x281936437478686720', 'Easy Phone', '55.064.824/0001-17', 'easyphonegyn@gmail.com', '(62) 9 8253-1403', '@easyphonegyn', 'AV OLINDA N 960 - SHOPPING LOZANDES - PISO TERREO - LOJA EASY PHONE', '//51806a6eef94fd6381ad6bd43b8e637b.cdn.bubble.io/f1743536594553x770851438877919100/IMG_9218.JPG', NULL, 'Gerencial', 'Anual', '2026-04-30T15:10:00', '2026-02-03T14:44:00', NULL, NULL, NULL, true, true, false, false, false, false, true, true, true, false, false, false, false, NULL, NULL, NULL, NULL, NULL, false, NULL, NULL, NULL, 'cus_000079267652', NULL, NULL, '1759220457797x679362008825619100', '96', NULL, NULL, NULL, NULL, '.I A garantia cobre os aparelhos lacrados/novos contra defeitos de fabricação durante um ano e cobre durante três meses os aparelhos seminovos, contado da data da compra pelo usuário final. Il. Aparelhos que apresentarem defeitos de fábrica (constatados por pericia técnica) em até sete dias corridos após a compra, a empresa se compromete em trocar o mesmo, por outro aparelho de mesmo modelo e qualidades, sem custo algum para o(a) cliente. I. A garantia não abrange funcionamento, instalação e atualização de aplicativos, bem como o sistema operacional do aparelho; Qualquer mau funcionamento APÓS ATUALIZAÇÕES do sistema operacional ou aplicativos; Limpeza e conservação do aparelho. IV. Os atendimentos no que tange a garantia dos aparelhos, serão prestados na loja física da empresa, ficando desde ao cliente ciente, que é de sua responsabilidade levar e buscar o aparelho, no referido endereço, caso necessite de garantia. V. No ato da compra, o cliente declara que foi informado que o WhatsApp específicos/oficiais para tratativas sobre garantia dos aparelhos Lé o telefone no cabeçalho da nota.', 'PADRAO', '2024-02-22T14:57:00', '2026-02-03T14:44:00', 'easyphonegyn@gmail.com');
