VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('Seu Fone LTDA') LIMIT 1), '1756314667448x270465369766372130', 'cus_000094421576', 'Parcela 4 de 12. TenFront - Anual - Essencial', '4.00', 'PAYMENT_RECEIVED', 'RECEIVED', 436.0, 436.0, 'Essencial', 'Anual', 1417.0, 61.61, '2024-09-24T00:00:00', '2026-11-11T15:47:00', NULL, true, false, NULL, NULL, 'Diego  Castro', '11955545602', 'Dourado', 'SP', 'Cliente ganho 01 mês por participação do evento do Luis e fechou assessoria com o Alef.  O cliente indiciou 02 clientes sob a condicional de que se eles fechassem antes do mês de outubro ganharia 30 dias por fechamento, porém se fosse após outubro ganharia 15 dias. Uma das indicações fechou em outubro e ele foi bonificado com 15 dias. Após isso indicou mais 02 clientes e foi bonificado com 15 dias, assim, ele teve um adicional de 30 dias de bonificação.', NULL, NULL, NULL, '2025-08-27T14:11:00', '2026-01-19T00:50:00', NULL);
