VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('Caio Capas') LIMIT 1), '1756314669358x843690452515558400', 'cus_000103845735', NULL, NULL, NULL, NULL, NULL, NULL, 'Essencial', 'Mensal', 447.0, 75.0, '2024-12-05T00:00:00', '2025-06-12T00:00:00', '2025-06-02T00:00:00', true, false, 'Cliente não tem usado a plataforma há pouco mais de um mês e gostaria de realizar o cancelamento. A loja é pequena e possui poucos processos e não tem funcionários.  Hoje, ele não possui computador na loja, somente seu pessoal e usa pouco, dessa forma está sendo muito trabalhoso pra ele separar um ou dois dias para fazer os lançamentos no sistema pelo computador. Ele não possui tablet e pelo celular é difícil pra ele por conta dos botões muito pequenos etc. Ele gostaria de cancelar agora, pois realmente não consegue utilizar, mas tem interesse em retornar quando tivermos o aplicativo mobile.', 'Aplicativo', 'Caio Felipe Gomes de Lima', '84991373737', 'Natal', 'RN', NULL, NULL, NULL, NULL, '2025-08-27T14:11:00', '2025-09-04T17:43:00', NULL);
