VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('BqEletronicos') LIMIT 1), '1756314669860x798480348457759000', 'cus_000106530105', 'TenFront - Mensal - Gerencial', NULL, 'PAYMENT_OVERDUE', 'OVERDUE', 0.0, 0.0, 'Gerencial', 'Mensal', 2670.0, 205.38, '2025-01-09T00:00:00', '2026-02-13T11:18:00', '2025-07-20T00:00:00', true, false, 'Cliente parou de pagar. Ela não aproveitava 100% das ferramentas e sempre pagava um pouco atrasado, esquecia de pagar. No último contato, ela falou que estava sem cartão de crédito e pediu pra ser via pix, enviamos o pix mas ela não pagou.', 'Falta de pagamento', 'Tuane  Conceição Bernardi', '47999231675', 'Brusque', 'SC', NULL, NULL, NULL, NULL, '2025-08-27T14:11:00', '2026-02-04T03:00:00', NULL);
