INSERT INTO assinaturas (empresa_id, bubble_unique_id, asaas_customer_id, asaas_descricao, asaas_parcela, asaas_evento, asaas_status, asaas_valor_recebido, mensalidade, plano, recorrencia, total_pago, ticket_medio, data_criacao_assinatura, data_acesso_ate, data_cancelamento, ativo, cancelado, motivo_cancelamento, tipo_motivo_cancelamento, nome_assinante, contato_assinante, cidade_assinante, uf_assinante, observacoes, forma_entrada, cupom_ativado, d_token, created_at, updated_at, created_by)
VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('IWin Botucatu') LIMIT 1), '1756314669908x500465664428432900', 'cus_000107007748', NULL, NULL, NULL, NULL, NULL, NULL, 'Essencial', 'Mensal', 745.0, 149.0, '2025-01-14T00:00:00', '2025-06-18T00:00:00', '2025-07-02T00:00:00', true, false, 'Cliente João Marcelo entrou em contato para solicitar o cancelamento, informou que ele mesmo gosta muito da TenFront mas os donos de cada loja tomam ações em conjunto, e em geral, foi decidido por outro sistema (pelas características que ele falou, é a Mercado Phone). Comentei com ele sobre o nosso CRM, ele falou que não sabia que nós tínhamos. Ofereci pra ele um upgrade na conta de Boituva para testar o CRM pelos próximos 20 dias (dias até a próxima renovação). Ele agradeceu, mas falou que vai deixar passar, falou que quer mesmo cancelar porque eles tiveram um gasto grande com a instalação do CRM nas 3 lojas e estão satisfeitos a nova plataforma também (falou que já faz dois meses que estão rodando a operação por lá).', 'CRM', 'Giovane Teodoro Alves Lima', '15996532668', 'Botucatu', 'SP', NULL, NULL, NULL, NULL, '2025-08-27T14:11:00', '2025-09-04T16:21:00', NULL);
