VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('ALGELIO COLOR KM 7') LIMIT 1), '1756314670446x165251935636586460', 'cus_000107883268', NULL, NULL, NULL, NULL, NULL, NULL, 'Estratégia', 'Mensal', 1318.0, 264.0, '2025-01-23T00:00:00', '2025-07-05T00:00:00', '2025-07-02T00:00:00', true, false, 'Cliente está fechando a loja, inclusive, já havíamos percebido que a loja estava com baixo fluxo de vendas. A cliente perguntou se ela voltar a pagar futuramente, se consegue acessar os dados novamente e eu confirmei (pode ser que eles retornem depois). Inclusive, conversando com o time, eles já comentaram em um treinamento que eles possuem mais lojas que não tem o sistema, eu já abri uma brecha com a cliente perguntando sobre trazer essas lojas pra cá, e ela falou: "Certo, mais pra frente nós podemos vê essa possibilidade 😉". Acredito que possa deixar no radar do comercial para entrar em contato no fim do mês ou no próximo (falar nessas próximas semanas não vai ser bom porque eles estarão lidando com o fechamento de uma das lojas).', 'Encerramento de atividades', 'Algelio Vieira', '94984416852', 'Marabá', 'PA', NULL, NULL, NULL, NULL, '2025-08-27T14:11:00', '2025-09-04T16:35:00', NULL);
