VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('Gonçalves Celulares') LIMIT 1), '1756314671219x799149709770057100', 'cus_000112641526', NULL, NULL, NULL, NULL, NULL, NULL, 'Gerencial', 'Mensal', 657.0, 219.0, '2025-03-13T00:00:00', '2025-06-14T00:00:00', '2025-06-12T00:00:00', true, false, 'Cliente estava conosco há 4 meses e realizou o treinamento no dia seguinte da sua contratação. Possui pouco histórico de contato com o suporte, geralmente de dúvidas simples. Cliente informou que ele e sua equipe não se adaptaram à plataforma, perguntei a ele se o suporte foi eficiente e o que ele considera que foi mais difícil e ele falou: "O suporte foi perfeito. Mas, em geral, foi a interface do sistema. É pouco diferente de um PDV normal."', 'Não se adaptou', 'Cleonilson Gonçalves Costa', '98981192342', 'São José de Ribamar', 'MA', NULL, NULL, NULL, NULL, '2025-08-27T14:11:00', '2025-09-04T17:22:00', NULL);
