INSERT INTO assinaturas (empresa_id, bubble_unique_id, asaas_customer_id, asaas_descricao, asaas_parcela, asaas_evento, asaas_status, asaas_valor_recebido, mensalidade, plano, recorrencia, total_pago, ticket_medio, data_criacao_assinatura, data_acesso_ate, data_cancelamento, ativo, cancelado, motivo_cancelamento, tipo_motivo_cancelamento, nome_assinante, contato_assinante, cidade_assinante, uf_assinante, observacoes, forma_entrada, cupom_ativado, d_token, created_at, updated_at, created_by)
VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('Dr Phone') LIMIT 1), '1756314672050x180793833201946300', 'cus_000113618649', NULL, NULL, NULL, NULL, NULL, NULL, 'Gerencial', 'Mesal', 249.0, 249.0, '2025-03-23T00:00:00', '2025-04-25T00:00:00', '2025-04-23T00:00:00', true, false, 'Conversando com o Rafael, ele me contou que testou outros 3 sistemas em paralelo, mas que a peça chave para essa decisão foi nos quesitos de Abertura de OS, ele gosta mt da TenFront, disse também que ela foi a melhor em vendas, porém o foco dele é assistência técnica e por isso tomou a decisão de mudar de sistema.  Pontos destaque para o Rafael em assistência técnica:   - Não ser possível reabrir uma OS para correção de erros eventuais.  - ⁠Não conseguir pesquisar por nome do cliente na hora de registar a OS dele. - ⁠Necessidade de ter que cadastrar completo um aparelho para OS.  - ⁠Ele acredita que esses detalhes acabam fazendo o cliente esperar muito tempo.', 'Funcionalidade', 'Rafael Teixeira Sampaio', '11971934410', NULL, NULL, NULL, NULL, NULL, NULL, '2025-08-27T14:11:00', '2025-09-05T15:36:00', NULL);
INSERT INTO assinaturas (empresa_id, bubble_unique_id, asaas_customer_id, asaas_descricao, asaas_parcela, asaas_evento, asaas_status, asaas_valor_recebido, mensalidade, plano, recorrencia, total_pago, ticket_medio, data_criacao_assinatura, data_acesso_ate, data_cancelamento, ativo, cancelado, motivo_cancelamento, tipo_motivo_cancelamento, nome_assinante, contato_assinante, cidade_assinante, uf_assinante, observacoes, forma_entrada, cupom_ativado, d_token, created_at, updated_at, created_by)
VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('RD Resolve Paulista') LIMIT 1), '1756314672068x189756903294115550', 'cus_000113623948', NULL, NULL, NULL, NULL, NULL, NULL, 'Assistência', 'Mesal', 189.0, 189.0, '2025-03-23T00:00:00', '2025-04-23T00:00:00', '2025-04-11T00:00:00', true, false, 'Cliente fechou na CBM, realizou o treinamento e foi entregue o acesso, porém entrou em contato hoje falando que gostaria de realizar o cancelamento, pois ele tentou (de acordo com ele, e muito) usar a plataforma, mas ele não se adaptou aos processos. Ele já tem a loja há um bom tempo e já possui processos definidos de assistência, ele falou que pra ele não compensa reformular os processos da loja para se adaptar ao sistema e incluiu que, para ele, o melhor seria pedir para alguém programar uma plataforma específica, pois nenhum sistema atende o que ele precisa. Ele ainda incluiu como sugestão já ter todos os tipos de celulares cadastrados na plataforma. Sobre os processos, ele achou muito trabalhoso abrir uma OS, cadastrar produtos e peças, incluir no estoque etc, sendo que às vezes, a manutenção é de coisas simples que demoram menos do que incluir no sistema.  O cliente ainda se colocou à disposição para auxiliar em processos de melhoria caso tenhamos interesse. Ele falou que tem interesse em ter um sistema e está disposto a retornar se atendermos às solicitações que ele fez.  Na minha visão, se implementarmos a OS expressa e cadastrarmos todos os modelos de celulares de forma padrão (não somente iPhones), já seria possível tentar resgatar esse cliente após o cancelamento.', 'Funcionalidade', 'Rodrigo Pereira', '11985869299', NULL, NULL, NULL, NULL, NULL, NULL, '2025-08-27T14:11:00', '2025-09-05T15:40:00', NULL);
