INSERT INTO assinaturas (empresa_id, bubble_unique_id, asaas_customer_id, asaas_descricao, asaas_parcela, asaas_evento, asaas_status, asaas_valor_recebido, mensalidade, plano, recorrencia, total_pago, ticket_medio, data_criacao_assinatura, data_acesso_ate, data_cancelamento, ativo, cancelado, motivo_cancelamento, tipo_motivo_cancelamento, nome_assinante, contato_assinante, cidade_assinante, uf_assinante, observacoes, forma_entrada, cupom_ativado, d_token, created_at, updated_at, created_by)
VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('Authentic Imports') LIMIT 1), '1756314673313x656594673677247900', 'cus_000122901085', 'TenFront - Mensal - Estrategia', NULL, 'PAYMENT_RECEIVED', 'RECEIVED', 0.0, 0.0, 'Estratégia', 'Mensal', 837.0, 279.0, '2025-06-16T00:00:00', '2025-09-17T00:00:00', '2025-08-28T00:00:00', true, false, 'Cliente entrou em contato com o suporte indagando a última cobrança feita, falando que cadastrou o cartão para realizar o pagamento do primeiro mês de teste, mas que não autorizou continuar cobrando. Verificando o histórico de mensagens com o comercial, em momento nenhum a cliente falou que iria só testar, e o comercial avisou ela sobre a cobrança recorrente. Avisei a cliente sobre a recorrência no cartão, ela compreendeu e informou que gostaria de cancelar. Perguntei o motivo e ela falou que não se adaptou ao sistema e que não gostou do CRM (que não atende a operação dela).', 'Não se adaptou', 'Marina Aparecida Teles Vieira', '47996189583', 'Gaspar', 'SC', NULL, NULL, NULL, NULL, '2025-08-27T14:11:00', '2025-09-17T00:14:00', NULL);
