VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('IWork Ltda.') LIMIT 1), '1756314673376x870803833404217200', 'cus_000123649268', 'TenFront - Mensal - Gerencial', NULL, 'PAYMENT_RECEIVED', 'RECEIVED', 0.0, 0.0, 'Gerencial', 'Mensal', 1345.0, 224.17, '2025-06-23T00:00:00', '2025-12-24T08:28:00', '2025-08-21T00:00:00', true, false, 'Cliente solicitou o cancelamento por motivos de falta de ferramentas essenciais para a operação dela, que seriam OS sequencial e etiqueta para OS. Ambas sugestões já foram aprovadas para implementação (dadas por outros clientes), porém sem data para finalização.  Falei isso pra ela e falei também que estamos trabalhando hoje na Nota Fiscal para OS (pois entendi que era algo importante pra operação dela tbm) porém ela falou que quer mesmo cancelar por enquanto, mas que futuramente poderá retornar.', 'Funcionalidade', 'Rayssa Oliveira', '11959597304', 'São José dos Campos', 'SP', NULL, NULL, NULL, NULL, '2025-08-27T14:11:00', '2025-11-24T00:41:00', NULL);
